<?php use App\Core\Helpers as H;use App\Services\EmailCampaignService;?><section class="panel"><div class="section-head"><h1>Email campaigns</h1><a class="btn" href="/admin/email-campaigns/new">New campaign</a></div><?php if(!$campaigns):?><p class="muted">No email campaigns have been created.</p><?php else:?><div class="table-scroll"><table><thead><tr><th>Subject</th><th>Audience</th><th>Status</th><th>Sent / total</th><th>Failed</th></tr></thead><tbody><?php foreach($campaigns as $c):?><tr><td><a href="/admin/email-campaigns/<?=(int)$c['id']?>"><?=H::e($c['subject'])?></a></td><td><?=H::e(EmailCampaignService::audienceLabel($c['audience']))?></td><td><?=H::e($c['status'])?></td><td><?=(int)$c['sent']?> / <?=(int)$c['total']?></td><td><?=(int)$c['failed']?></td></tr><?php endforeach;?></tbody></table></div><?php endif;?></section>
